if (! function_exists('emoji_art_renderer')) {
    function emoji_art_renderer($grid, $separator = null, $align = null)
    {
        if (!is_array($grid) || empty($grid)) {
            return json_encode(['error' => 'Grid must be a non-empty 2D array']);
        }
        $separator = isset($separator) ? $separator : ' ';
        $align = isset($align) ? $align : 'left';

        $output = [];
        $maxCols = 0;
        foreach ($grid as $row) {
            if (is_array($row)) {
                $maxCols = max($maxCols, count($row));
            }
        }

        // Calculate column widths for alignment
        $colWidths = array_fill(0, $maxCols, 0);
        foreach ($grid as $rowIdx => $row) {
            if (!is_array($row)) continue;
            foreach ($row as $colIdx => $cell) {
                $len = mb_strlen((string)$cell);
                $colWidths[$colIdx] = max($colWidths[$colIdx], $len);
            }
        }

        $rendered = [];
        foreach ($grid as $rowIdx => $row) {
            if (!is_array($row)) {
                $rendered[] = (string)$row;
                continue;
            }
            $cells = [];
            for ($i = 0; $i < $maxCols; $i++) {
                $cell = isset($row[$i]) ? (string)$row[$i] : '';
                $width = $colWidths[$i];
                switch ($align) {
                    case 'center':
                        $padding = $width - mb_strlen($cell);
                        $left = (int)($padding / 2);
                        $right = $padding - $left;
                        $cells[] = str_repeat(' ', max(0, $left)) . $cell . str_repeat(' ', max(0, $right));
                        break;
                    case 'right':
                        $cells[] = str_repeat(' ', max(0, $width - mb_strlen($cell))) . $cell;
                        break;
                    case 'left':
                    default:
                        $cells[] = $cell . str_repeat(' ', max(0, $width - mb_strlen($cell)));
                        break;
                }
            }
            $rendered[] = implode($separator, $cells);
        }

        $result = implode("\n", $rendered);

        return json_encode([
            'rendered' => $result,
            'rows' => count($rendered),
            'cols' => $maxCols,
            'characters' => mb_strlen($result)
        ]);
    }
